<svg viewBox="0 0 700 360" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Projekt Nova: vom Bitcoin-Halten zum Finanzökosystem</text>
  <g font-family="sans-serif">
    <rect x="24" y="52" width="200" height="92" rx="10" fill="#1c1c1f" stroke="#f7931a" stroke-width="1.5"/>
